                </div>
                <p className="text-xs font-bold leading-relaxed opacity-80">
                    All mining cycles are secured by multi-signature smart contracts on the TRON network.
                </p>
            </motion.div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

