    const currentActive = activePackages.find(ap => ap.isActive);
    const isCurrent = currentActive?.packageId === pkg.id;
    let isDisabled = false;
    let buttonText = "Deploy";
    let extraInfo = "";
    let isLocked = false;
    let cost = pkg.minAmount;

    if (currentActive) {
        if (isCurrent) { buttonText = "Active"; isDisabled = true; } 
        else if (pkg.minAmount <= currentActive.amount) { buttonText = "N/A"; isDisabled = true; extraInfo = "No downgrades"; } 
        else {
