// RECURSIVE SANITIZER: Handles deep objects and arrays to stripping Firestore internals
const sanitizeValue = (val: any): any => {
    if (!val) return val;
    // Handle Timestamps
    if (typeof val.toMillis === 'function') return val.toMillis();
    // Handle References
    if (typeof val === 'object' && typeof val.path === 'string' && typeof val.id === 'string') return val.path;
    // Handle Arrays
    if (Array.isArray(val)) return val.map(sanitizeValue);
    // Handle Objects
    if (typeof val === 'object') {
        // Strip Firestore internals
        if ('firestore' in val || '_key' in val || 'converter' in val) return null;

        const cleanObj: any = {};
        Object.keys(val).forEach(k => {
            const cleaned = sanitizeValue(val[k]);
            // Only add if not null (unless it was originally null)
            if (cleaned !== null || val[k] === null) {
                cleanObj[k] = cleaned;
            }
        });
        return cleanObj;
    }
    return val;
};

const sanitizeDoc = (docSnap: any) => {
    if (!docSnap.exists()) return null;
    const data = docSnap.data();
    const clean: any = { id: docSnap.id };

    Object.keys(data).forEach(key => {
        clean[key] = sanitizeValue(data[key]);
    });
    return clean;
};

