export const requestFiatDeposit = async (
  userId: string,
  amountNgn: number,
  exchangeRate: number,
  proofImage: string,
  adminBankId: string
) => {
  const amountUsdt = amountNgn / exchangeRate;

  const reqRef = doc(collection(db, 'fiat_requests'));
